strings = ["abcabcbb", "bbbbb", "pwwkew", ""]

def longest_unique(s):
    seen, left, best = set(), 0, 0
    for right, ch in enumerate(s):
        while ch in seen:
            seen.remove(s[left]); left += 1
        seen.add(ch)
        best = max(best, right - left + 1)
    return best

for s in strings:
    print(longest_unique(s))

