cases = [
    [1, 2, 3, 1],
    [2, 7, 9, 3, 1],
    [5],
]

def rob(nums):
    prev2 = prev1 = 0
    for n in nums:
        prev2, prev1 = prev1, max(prev1, prev2 + n)
    return prev1

for nums in cases:
    print(rob(nums))
